'use strict';

// MODULES //

import isComplexFloatingPointDataType from '@stdlib/ndarray-base-assert-is-complex-floating-point-data-type'; // eslint-disable-line id-length
import emptyLike from '@stdlib/ndarray-base-empty-like';
import fill from '@stdlib/ndarray-base-fill';
import dtype from '@stdlib/ndarray-base-dtype';
import CNAN from '@stdlib/constants-complex128-nan';


// MAIN //

/**
* Creates a NaN-filled ndarray having the same shape and data type as a provided ndarray.
*
* @param {ndarray} x - input array
* @returns {ndarray} ndarray
*
* @example
* import getShape from '@stdlib/ndarray-shape';
* import getDType from '@stdlib/ndarray-dtype';
* import ones from '@stdlib/ndarray-ones';
*
* var x = ones( [ 2, 2 ], {
*     'dtype': 'float32'
* });
* // returns <ndarray>[ [ 1.0, 1.0 ], [ 1.0, 1.0 ] ]
*
* var y = nansLike( x );
* // returns <ndarray>[ [ NaN, NaN ], [ NaN, NaN ] ]
*
* var sh = getShape( y );
* // returns [ 2, 2 ]
*
* var dt = String( getDType( y ) );
* // returns 'float32'
*/
function nansLike( x ) {
	if ( isComplexFloatingPointDataType( dtype( x ) ) ) {
		return fill( emptyLike( x ), CNAN );
	}
	return fill( emptyLike( x ), NaN );
}


// EXPORTS //

export default nansLike;
